import json
import hashlib
from collections import defaultdict
from dataclasses import dataclass, field

class DeduplicationRing:
    def __init__(self):
        self._hashes = set()
    def content_hash(self, r):
        return hashlib.sha256(json.dumps(r, sort_keys=True).encode()).hexdigest()
    def mark_processed(self, r):
        self._hashes.add(self.content_hash(r))
    def __len__(self):
        return len(self._hashes)

@dataclass
class PhaseResult:
    phase_name: str
    items: list
    errors: list = field(default_factory=list)

records = [
    {"id": "V-1", "vendor_name": "Medtronic PLC", "city": "Minneapolis"},
    {"id": "V-2", "vendor_name": "j&j  inc.", "city": "new brunswick"},
    {"id": "V-3", "vendor_name": "ABBOTT labs, corp.", "city": "abbott park"},
    {"id": "V-4", "vendor_name": "NewVenture BioTech", "city": "Cambridge"},
    {"id": "V-5", "vendor_name": "stryker corporation", "city": "kalamazoo"}
]

entities = [
    {"id": "E-1", "canonical_name": "Medtronic PLC"},
    {"id": "E-2", "canonical_name": "Johnson & Johnson"},
    {"id": "E-3", "canonical_name": "Abbott Laboratories"},
    {"id": "E-4", "canonical_name": "Stryker Corporation"}
]
symbol_table = "\n".join(f"  {e['id']}: {e['canonical_name']}" for e in entities)

dedup = DeduplicationRing()

prompts = [
    f"Triage: {{record_id, disposition (exact_match|fuzzy_match|anomaly), confidence, matched_entity_id, rationale}}.\nEntities:\n{symbol_table}\nRecord: {json.dumps(r)}"
    for r in records
]
raw = llm_query_batched(prompts)

decisions = []
for r, resp in zip(records, raw):
    obj = json.loads(resp.strip())
    decisions.append(obj)
    dedup.mark_processed(r)

buckets = defaultdict(list)
for d in decisions:
    buckets[d["disposition"]].append(d)

anomalies = buckets.get("anomaly", [])
print(f"Turn 1 results: {len(decisions)} triaged")
for disp, items in sorted(buckets.items()):
    print(f"  {disp}: {len(items)}")
print(f"Anomalies to investigate: {[a['record_id'] for a in anomalies]}")
turn1_anomalies = anomalies
